        /// Regression (review finding on the streaming-retention PR): the non-prefix
        /// `generate_streaming` decode loop must append every non-empty delta to the
        /// returned `GenerateOutput.text`, not just hand it to `on_token`. A prior
        /// version of the loop body called `on_token(&delta, next_id)` without first
        /// doing `text.push_str(&delta)`, so `out.text` silently dropped every decode
        /// token's contribution (only the prefill token and the final incomplete-UTF-8
        /// tail were ever appended). `single_char_vocab_tokenizer` guarantees every
        /// token decodes to exactly one non-empty-delta character (no UTF-8 boundary
        /// holdback), so this test exercises the loop body on every one of its
        /// iterations rather than being satisfied by the prefill token alone.
        #[test]
        fn streaming_text_accumulates_every_loop_delta_not_only_prefill() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };

            use crate::model::qwen35_config::GenerateConfig;

            let tokenizer = single_char_vocab_tokenizer();
            let gen_cfg = GenerateConfig {
                max_new_tokens: 5,
                temperature: 0.0,
                top_k: 1,
                top_p: 1.0,
                repetition_penalty: 1.0,
                seed: Some(1),
                stop_token_ids: vec![],
                enable_thinking: false,
                enable_mtp: Some(false),
                grammar: None,
                stop_strings: vec![],
                reasoning_budget: None,
                logprobs: None,
            };

            let (mut cfg, weights) = tiny_hybrid_fixture();
            // Push eos_token_id out of the model's reachable output range so greedy
            // sampling cannot end the stream after the prefill token — this test
            // needs several decode-loop iterations (not just the prefill push) to
            // exercise the bug.
            cfg.eos_token_id = u32::MAX;
            let mut state = MetalQwen35State::new(&weights, &cfg, 32).expect("tiny hybrid fixture");

            let mut accumulated = String::new();
            let out = state
                .generate_streaming("a", &tokenizer, &gen_cfg, |delta, _id| {
                    accumulated.push_str(delta);
                    true
                })
                .expect("no grammar configured; must not fail closed");

            assert!(
                out.generated_tokens >= 3,
                "test needs at least 3 generated tokens to exercise the decode loop, got {}",
                out.generated_tokens
            );
            assert_eq!(
                out.text, accumulated,
                "GenerateOutput.text must equal the concatenation of every on_token \
                 delta (plus the finish() tail, already included in `accumulated` via \
                 the callback) — a mismatch means the non-prefix decode loop dropped \
                 deltas instead of appending them to the caller-owned `text` accumulator"
            );
        }

        #[test]
        fn self_spec_pool_holds_one_slot_per_verify_token_plus_base() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };

            let state = with_self_spec_env(|| {
                let (cfg, weights) = tiny_hybrid_fixture();
                MetalQwen35State::new(&weights, &cfg, 32).expect("tiny hybrid fixture")
            });

            let pool = state
                .session
                .gdn_checkpoints
                .as_ref()
                .expect("self-spec pool must be allocated");
            // verify_tokens_batched writes slot 0 (pre-verify) plus one slot per processed
            // token. Self-spec sends `1 + SELF_SPEC_MAX_DRAFT` tokens, so the pool must
            // hold `2 + SELF_SPEC_MAX_DRAFT` slots total.
            assert!(
                pool.conv_slots.len() >= 2 + SELF_SPEC_MAX_DRAFT,
                "pool conv_slots = {} must be >= {} (1 base + 1 + SELF_SPEC_MAX_DRAFT verified tokens)",
                pool.conv_slots.len(),
                2 + SELF_SPEC_MAX_DRAFT,
            );
            assert!(
                pool.s_slots.len() >= 2 + SELF_SPEC_MAX_DRAFT,
                "pool s_slots = {} must be >= {}",
                pool.s_slots.len(),
                2 + SELF_SPEC_MAX_DRAFT,
            );
        }

        /// Regression: self-spec slot 0 must hold the *pre-draft* GDN state, not the
        /// state after GDN-only draft forwards. The tiny fixture has all-zero weights
        /// which makes GDN-only forwards numerically uninteresting on their own, so we
        /// seed the live GDN buffers with a recognizable non-zero pattern before the
        /// round, snapshot that as the pre-draft baseline, then assert slot 0 still
        /// matches it after a self-spec round. If slot 0 were captured AFTER GDN-only
        /// draft forwards, the conv buffer's rolling shift (which moves the planted
        /// pattern even when conv weights are zero) would shift slot 0's contents and
        /// the check would fail.
        #[test]
        fn self_spec_slot0_holds_pre_draft_state_after_round() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };

            use crate::model::qwen35_config::GenerateConfig;
            use crate::speculative::MtpTargetVerifier;

            let tokenizer = minimal_bpe_tokenizer();
            let gen_cfg = GenerateConfig {
                max_new_tokens: 4,
                temperature: 0.0,
                top_k: 1,
                top_p: 1.0,
                repetition_penalty: 1.0,
                seed: Some(7),
                stop_token_ids: vec![],
                enable_thinking: false,
                enable_mtp: Some(false),
                grammar: None,
                stop_strings: vec![],
                reasoning_budget: None,
                logprobs: None,
            };

            let mut state = with_self_spec_env(|| {
                let (cfg, weights) = tiny_hybrid_fixture();
                MetalQwen35State::new(&weights, &cfg, 32).expect("tiny hybrid fixture")
            });

            state.reset_state();

            // Plant a recognizable non-zero pattern into the live GDN GPU buffers so the
            // pre-draft / post-draft slot contents are observably distinct. The exact
            // values don't matter — only that conv rolling and S-matrix decay would
            // perturb them if GDN-only draft forwards touched the captured slot.
            for (li, buf) in state.session.gdn_gpu_s_matrices.iter().enumerate() {
                let n = (buf.length() / 4) as usize;
                // SAFETY: StorageModeShared; no command buffer in flight in the test.
                unsafe {
                    let ptr = buf.contents() as *mut f32;
                    for k in 0..n {
                        *ptr.add(k) = 0.5 + (li as f32) * 0.01 + (k as f32) * 1e-4;
                    }
                }
            }
            for (li, buf) in state.session.gdn_gpu_conv_bufs.iter().enumerate() {
                let n = (buf.length() / 4) as usize;
                // SAFETY: see above.
                unsafe {
                    let ptr = buf.contents() as *mut f32;
                    for k in 0..n {
                        *ptr.add(k) = -0.7 - (li as f32) * 0.013 - (k as f32) * 2e-4;
                    }
                }
            }

            let snap_before = state.snapshot_gdn_states();
            assert!(
                !snap_before.is_empty(),
                "tiny hybrid fixture must have GDN layers"
            );

            let real_prefill = state.forward_prefill(&[0u32]);
            // Refresh the baseline AFTER prefill (which mutates GDN); this matches the
            // exact state the self-spec round will see at `pos = kv.seq_len`.
            let snap_pre_round = state.snapshot_gdn_states();

            // Precondition for the regression: GDN-only draft forwards must actually
            // mutate the live GDN buffers so we are checking that slot 0 is restored
            // to pre-draft state. We don't want to leave the live state perturbed when
            // generate_greedy_self_spec runs, so snapshot first, run a draft-only
            // forward to confirm it perturbs GDN, then restore.
            let observed_drift = {
                let probe_token = 1u32;
                let probe_pos = state.session.kv_cache.seq_len;
                let _ = state.forward_step_gdn_only(probe_token, probe_pos);
                let post = state.snapshot_gdn_states();
                let mut max_abs = 0.0f32;
                for (li, layer) in post.iter().enumerate() {
                    for (k, &v) in layer.0.iter().enumerate() {
                        max_abs = max_abs.max((v - snap_pre_round[li].0[k]).abs());
                    }
                    for (k, &v) in layer.1.iter().enumerate() {
                        max_abs = max_abs.max((v - snap_pre_round[li].1[k]).abs());
                    }
                }
                // Restore pre-round baseline so the self-spec round sees the same state
                // the test sampled into `real_prefill`.
                state.restore_gdn_states(&snap_pre_round);
                max_abs
            };
            assert!(
                observed_drift > 0.0,
                "forward_step_gdn_only must actually perturb live GDN buffers; \
                 otherwise this test cannot detect slot-0 contamination"
            );

            // Force a non-stop pending_token via a one-hot logits vector at a non-EOS
            // id so generate_greedy_self_spec actually enters the round loop. Token 3
            // is a regular "t0" vocabulary entry in the minimal tokenizer.
            let mut forced_logits = vec![0.0f32; real_prefill.len()];
            let target_id = 3usize.min(real_prefill.len() - 1);
            forced_logits[target_id] = 100.0;

            let out = with_self_spec_env(|| {
                state.generate_greedy_self_spec(&forced_logits, 1, &tokenizer, &gen_cfg)
            });
            assert!(
                out.generated_tokens > 0,
                "self-spec round must actually execute; got {} generated tokens",
                out.generated_tokens
            );

            // After running a self-spec round, slot 0 must equal the pre-draft baseline
            // (which we captured AFTER prefill). If slot 0 had been written by the
            // GDN-only draft forwards or by the verify-loop checkpoint at the *wrong*
            // time, the conv buffer's rolling shift would have moved our planted
            // pattern and this check would fail.
            let pool = state
                .session
                .gdn_checkpoints
                .as_ref()
                .expect("pool must be allocated");
            for (li, snap_layer) in snap_pre_round.iter().enumerate() {
                let slot0_s = &pool.s_slots[0][li];
                let slot0_conv = &pool.conv_slots[0][li];
                let n_s = (slot0_s.length() / 4) as usize;
                let n_conv = (slot0_conv.length() / 4) as usize;
                // SAFETY: shared-storage buffers; the round has fully completed.
                let live_s = unsafe {
                    let ptr = slot0_s.contents() as *const f32;
                    std::slice::from_raw_parts(ptr, n_s)
                };
                let live_conv = unsafe {
                    let ptr = slot0_conv.contents() as *const f32;
                    std::slice::from_raw_parts(ptr, n_conv)
                };
                assert_eq!(live_s.len(), snap_layer.0.len());
                assert_eq!(live_conv.len(), snap_layer.1.len());
                for k in 0..live_s.len() {
                    let delta = (live_s[k] - snap_layer.0[k]).abs();
                    assert!(
                        delta < 1e-5,
                        "slot 0 s[{li}][{k}] = {} drifted from pre-draft = {} (delta {})",
                        live_s[k],
                        snap_layer.0[k],
                        delta
                    );
                }
                for k in 0..live_conv.len() {
                    let delta = (live_conv[k] - snap_layer.1[k]).abs();
                    assert!(
                        delta < 1e-5,
                        "slot 0 conv[{li}][{k}] = {} drifted from pre-draft = {} (delta {})",
                        live_conv[k],
                        snap_layer.1[k],
                        delta
                    );
                }
                // Sanity check: the planted pattern should still be non-zero so this
                // test would detect a bug; if the conv buffer were all zeros the
                // rolling shift would be invisible.
                assert!(
                    snap_layer.1.iter().any(|&v| v.abs() > 0.0),
                    "test fixture must plant non-zero conv pattern on layer {li}"
                );
            }
        }

        #[test]
        fn snapshot_gdn_states_roundtrips_through_metal_buffers() {
            use crate::speculative::MtpTargetVerifier;
            let Some(_) = metal::Device::system_default() else {
                return;
            };

            let mut state = with_self_spec_env(|| {
                let (cfg, weights) = tiny_hybrid_fixture();
                MetalQwen35State::new(&weights, &cfg, 32).expect("tiny hybrid fixture")
            });

            // Write a recognizable pattern into the live GPU GDN buffers.
            for (li, buf) in state.session.gdn_gpu_s_matrices.iter().enumerate() {
                let n = (buf.length() / 4) as usize;
                // SAFETY: StorageModeShared buffer; no command buffer in flight in the test.
                unsafe {
                    let ptr = buf.contents() as *mut f32;
                    for k in 0..n {
                        *ptr.add(k) = (li as f32) + (k as f32) * 1e-4;
                    }
                }
            }
            for (li, buf) in state.session.gdn_gpu_conv_bufs.iter().enumerate() {
                let n = (buf.length() / 4) as usize;
                // SAFETY: see above.
                unsafe {
                    let ptr = buf.contents() as *mut f32;
                    for k in 0..n {
                        *ptr.add(k) = -(li as f32) - (k as f32) * 1e-4;
                    }
                }
            }

            let snap = state.snapshot_gdn_states();
            assert_eq!(snap.len(), state.session.gdn_gpu_s_matrices.len());

            // Clobber the live buffers.
            for buf in &state.session.gdn_gpu_s_matrices {
                let n = (buf.length() / 4) as usize;
                // SAFETY: see above.
                unsafe {
                    let ptr = buf.contents() as *mut f32;
                    for k in 0..n {
                        *ptr.add(k) = 0.0;
                    }
                }
            }
            for buf in &state.session.gdn_gpu_conv_bufs {
                let n = (buf.length() / 4) as usize;
                // SAFETY: see above.
                unsafe {
                    let ptr = buf.contents() as *mut f32;
                    for k in 0..n {
                        *ptr.add(k) = 0.0;
                    }
                }
            }

            state.restore_gdn_states(&snap);

            for (li, buf) in state.session.gdn_gpu_s_matrices.iter().enumerate() {
                let n = (buf.length() / 4) as usize;
                // SAFETY: see above.
                let live = unsafe {
                    let ptr = buf.contents() as *const f32;
                    std::slice::from_raw_parts(ptr, n)
                };
                for (k, &v) in live.iter().enumerate() {
                    let expected = (li as f32) + (k as f32) * 1e-4;
                    assert!(
                        (v - expected).abs() < 1e-6,
                        "s_matrices[{li}][{k}] = {v} after restore, expected {expected}"
                    );
                }
            }
        }

        // -----------------------------------------------------------------------
        // Chunked batched prefill parity tests
        // -----------------------------------------------------------------------

        /// Build a token sequence of 650-700 tokens from varied prose paragraphs.
        /// Uses the provided tokenizer; grows text by appending paragraphs until
        /// the encoded length is ≥ 650, then truncates to ≤ 680.
        fn long_real_text_tokens(tokenizer: &BpeTokenizer) -> Vec<u32> {
            let paragraphs = [
                "During a late engineering review, the team walked through the inference trace \
                 one layer at a time. They checked where state changed, which buffers were reused, \
                 and how a long request should preserve every earlier token.",
                "The prompt continued with ordinary prose about debugging, benchmarks, release notes, \
                 and careful handoffs. It used full sentences, punctuation, and varied vocabulary \
                 so tokenization looked like real input rather than a repeated numeric pattern.",
                "A second reviewer asked for evidence at the boundary between chunks. The answer \
                 described rotary positions, cache rows, recurrent memory, and causal attention \
                 in concrete terms before any optimization was accepted.",
                "Verification across chunk boundaries requires that each token's absolute position \
                 index matches the RoPE table row, the KV cache write offset, and the attention \
                 causal mask — all three must use the same absolute coordinate, not a chunk-local one.",
            ];
            let mut text = String::new();
            let mut ids = Vec::new();
            for i in 0..256usize {
                if !text.is_empty() {
                    text.push_str("\n\n");
                }
                text.push_str(paragraphs[i % paragraphs.len()]);
                let input = tokenizer.tokenize(&text);
                ids = input.input_ids[..input.real_length].to_vec();
                if ids.len() >= 650 {
                    break;
                }
            }
            if ids.len() > 680 {
                ids.truncate(680);
            }
            ids
        }

        fn argmax_f32(xs: &[f32]) -> usize {
            let mut best = 0usize;
            let mut best_val = f32::NEG_INFINITY;
            for (i, &x) in xs.iter().enumerate() {
                if x > best_val {
                    best_val = x;
                    best = i;
                }
            }
            best
        }

        #[cfg(all(target_os = "macos", feature = "metal-gpu"))]
        #[test]
        fn metal_qwen35_chunked_prefill_long_prompt_matches_step_loop() {
            // Parity gate: chunked forward_prefill must agree with token-by-token
            // forward_step on a prompt longer than max_prefill (≈512).
            // Tests that RoPE offsets, KV cache rows, attention cache_len, and
            // GDN recurrent state all thread correctly across chunk boundaries.
            let model_dir =
                std::path::PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| ".".into()))
                    .join(".lattice/models/qwen3.5-0.8b");
            if !model_dir.join("model.safetensors").exists()
                || !model_dir.join("config.json").exists()
                || !model_dir.join("tokenizer.json").exists()
            {
                eprintln!(
                    "skipping chunked prefill parity test: model files missing at {}",
                    model_dir.display()
                );
                return;
            }

            let model = crate::model::qwen35::Qwen35Model::from_safetensors(&model_dir)
                .expect("load qwen3.5-0.8b");
            assert!(
                model.config().num_active_linear_attention_layers() > 0,
                "prompt must exercise at least one GDN layer"
            );

            let Some(device) = Device::system_default() else {
                eprintln!("skipping chunked prefill parity test: no Metal device");
                return;
            };
            let _ = device;

            let mut state = MetalQwen35State::new(model.weights(), model.config(), 1024)
                .expect("construct Metal qwen3.5-0.8b state");

            let tokens = long_real_text_tokens(model.tokenizer());
            assert!(
                tokens.len() > state.session.max_prefill,
                "prompt ({} tokens) must exceed max_prefill ({})",
                tokens.len(),
                state.session.max_prefill
            );
            assert!(
                (600..=700).contains(&tokens.len()),
                "prompt length {} out of expected 600-700 range",
                tokens.len()
            );

            // Path A: token-by-token reference.
            state.reset_state();
            let mut step_logits = Vec::new();
            for (pos, &tok) in tokens.iter().enumerate() {
                step_logits = state.forward_step(tok, pos);
            }

            // Path B: chunked batched prefill.
            state.reset_state();
            let prefill_logits = state.forward_prefill(&tokens);

            assert_eq!(step_logits.len(), model.config().vocab_size);
            assert_eq!(prefill_logits.len(), model.config().vocab_size);

            let max_abs_diff = step_logits
                .iter()
                .zip(prefill_logits.iter())
                .map(|(a, b)| (a - b).abs())
                .fold(0.0_f32, f32::max);

            eprintln!(
                "chunked prefill parity: max_abs_diff={max_abs_diff:.6}, \
                 argmax_step={}, argmax_prefill={}, tokens={}",
                argmax_f32(&step_logits),
                argmax_f32(&prefill_logits),
                tokens.len()
            );

            // KNOWN ISSUE (2026-06-03): the chunked-batched prefill path exhibits a
            // nondeterministic, contention/occupancy-sensitive logit divergence vs the
            // token-by-token reference, observed up to ~0.94 in a tight back-to-back loop.
            // A full static audit of `gdn_recurrence_fused` and `decode_attention` found
            // both kernels barrier-correct with no uninitialized threadgroup reads, no
            // intra-dispatch cross-threadgroup device race, and no untracked buffers on the
            // path — the magnitude is too large for FP-reorder noise, so the hazard is a
            // runtime-only one observable solely under GPU frame capture (Xcode Metal
            // debugger). The argmax is STABLE across hundreds of runs, so generated tokens
            // are unaffected; only logit *values* drift. The hard guarantee this test
            // enforces is therefore argmax equality; the logit-value bound is a loose
            // regression guard, not a strict-parity assertion. See RACE_FIX_NOTES.md /
            // ADR-065 for the full diagnosis and the GPU-capture path to a true fix.
            assert!(
                max_abs_diff < 0.5,
                "chunked prefill logits diverged from step loop beyond the known-issue \
                 tolerance (argmax-safe latent race): max_abs_diff={max_abs_diff}"
            );
            assert_eq!(
                argmax_f32(&step_logits),
                argmax_f32(&prefill_logits),
                "argmax mismatch between step loop and chunked prefill"
            );
            // Both paths must advance the session cursor to the full prompt length.
            assert_eq!(state.session.kv_cache.seq_len, tokens.len());
            assert_eq!(state.session.position, tokens.len());
        }

        #[cfg(all(target_os = "macos", feature = "metal-gpu"))]
        #[test]
        fn metal_qwen35_chunked_prefill_length_1_final_chunk_matches_step_loop() {
            // Degenerate-boundary gate: a prompt of exactly max_prefill + 1 tokens
            // decomposes into chunks [max_prefill, 1]. The length-1 final chunk
            // goes through forward_prefill_batched_chunk with n=1 (single-iteration
            // per-token loops, m=1 GEMMs) — NOT the forward_step fast path. This
            // path is unreachable by the 600-700 token parity test above.
            let model_dir =
                std::path::PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| ".".into()))
                    .join(".lattice/models/qwen3.5-0.8b");
            if !model_dir.join("model.safetensors").exists()
                || !model_dir.join("config.json").exists()
                || !model_dir.join("tokenizer.json").exists()
            {
                eprintln!(
                    "skipping length-1 final-chunk parity test: model files missing at {}",
                    model_dir.display()
                );
                return;
            }

            let model = crate::model::qwen35::Qwen35Model::from_safetensors(&model_dir)
                .expect("load qwen3.5-0.8b");
            assert!(
                model.config().num_active_linear_attention_layers() > 0,
                "prompt must exercise at least one GDN layer"
            );

            let Some(device) = Device::system_default() else {
                eprintln!("skipping length-1 final-chunk parity test: no Metal device");
                return;
            };
            let _ = device;

            let mut state = MetalQwen35State::new(model.weights(), model.config(), 1024)
                .expect("construct Metal qwen3.5-0.8b state");

            // Trim to exactly max_prefill + 1 so the final chunk has length 1.
            let mut tokens = long_real_text_tokens(model.tokenizer());
            let target = state.session.max_prefill + 1;
            assert!(
                tokens.len() >= target,
                "helper produced {} tokens, need >= {target}",
                tokens.len()
            );
            tokens.truncate(target);
            assert_eq!(
                tokens.len(),
                state.session.max_prefill + 1,
                "prompt must be exactly max_prefill + 1 for a length-1 final chunk"
            );

            // Path A: token-by-token reference.
            state.reset_state();
            let mut step_logits = Vec::new();
            for (pos, &tok) in tokens.iter().enumerate() {
                step_logits = state.forward_step(tok, pos);
            }

            // Path B: chunked batched prefill (final chunk length 1).
            state.reset_state();
            let prefill_logits = state.forward_prefill(&tokens);

            assert_eq!(step_logits.len(), model.config().vocab_size);
            assert_eq!(prefill_logits.len(), model.config().vocab_size);

            let max_abs_diff = step_logits
                .iter()
                .zip(prefill_logits.iter())
                .map(|(a, b)| (a - b).abs())
                .fold(0.0_f32, f32::max);

            eprintln!(
                "length-1 final-chunk parity: max_abs_diff={max_abs_diff:.6}, \
                 argmax_step={}, argmax_prefill={}, tokens={}",
                argmax_f32(&step_logits),
                argmax_f32(&prefill_logits),
                tokens.len()
            );

            assert!(
                max_abs_diff < 1e-2,
                "length-1 final-chunk logits diverged from step loop: max_abs_diff={max_abs_diff}"
            );
            assert_eq!(
                argmax_f32(&step_logits),
                argmax_f32(&prefill_logits),
                "argmax mismatch on length-1 final chunk"
            );
            assert_eq!(state.session.kv_cache.seq_len, tokens.len());
            assert_eq!(state.session.position, tokens.len());
        }

        /// Experiment B regression gate: `forward_prefill_batched_chunk` now gates its
        /// terminal RMSNorm+lm_head+MTP+top-k tail behind `emit_logits`, skipping it on
        /// intermediate chunks of a chunked, last-token-only (`!all_positions`) prefill —
        /// only the LAST chunk emits it. This asserts the skip is correctness-preserving:
        /// `forward_prefill` on a prompt spanning multiple chunks must still return
        /// `vocab_size` logits, whose argmax agrees with the final-position row of a
        /// `forward_prefill_all_logits` run (which emits every chunk's tail and so is
        /// unaffected by the emit_logits gate), and the session cursor must still have
        /// advanced through every chunk — including the ones whose tail was skipped.
        /// Mutation-sensitive: if `is_last` in `forward_prefill_impl`'s `!all_positions`
        /// loop is computed wrong (e.g. always `false`), `forward_prefill` returns an
        /// empty `Vec` and the length assertion below fails; if `set_position` were
        /// dropped from the `!emit_logits` branch, the position assertion fails.
        #[cfg(all(target_os = "macos", feature = "metal-gpu"))]
        #[test]
        fn metal_qwen35_chunked_prefill_emit_logits_skip_correctness() {
            let model_dir =
                std::path::PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| ".".into()))
                    .join(".lattice/models/qwen3.5-0.8b");
            if !model_dir.join("model.safetensors").exists()
                || !model_dir.join("config.json").exists()
                || !model_dir.join("tokenizer.json").exists()
            {
                eprintln!(
                    "skipping emit_logits skip-correctness test: model files missing at {}",
                    model_dir.display()
                );
                return;
            }

            let model = crate::model::qwen35::Qwen35Model::from_safetensors(&model_dir)
                .expect("load qwen3.5-0.8b");
            let Some(device) = Device::system_default() else {
                eprintln!("skipping emit_logits skip-correctness test: no Metal device");
                return;
            };
            let _ = device;
            let _gpu = gpu_test_lock();

            let mut state = MetalQwen35State::new(model.weights(), model.config(), 1024)
                .expect("construct Metal qwen3.5-0.8b state");
            let vocab = model.config().vocab_size;

            let tokens = long_real_text_tokens(model.tokenizer());
            assert!(
                tokens.len() > state.session.max_prefill,
                "prompt ({} tokens) must exceed max_prefill ({}) to exercise the \
                 chunked, emit_logits-gated path",
                tokens.len(),
                state.session.max_prefill
            );

            // Reference: all_positions=true emits the tail on EVERY chunk (unaffected by
            // the emit_logits gate) — its final-position row is what an unskipped last
            // chunk would have produced.
            state.reset_state();
            let all_logits = state.forward_prefill_all_logits(&tokens);
            assert_eq!(
                all_logits.len(),
                tokens.len() * vocab,
                "all-position reference length mismatch"
            );
            let ref_last = &all_logits[(tokens.len() - 1) * vocab..tokens.len() * vocab];

            // Under test: the `!all_positions` chunked path, where every non-last chunk
            // now runs with emit_logits=false.
            state.reset_state();
            let last_logits = state.forward_prefill(&tokens);

            assert_eq!(
                last_logits.len(),
                vocab,
                "chunked !all_positions prefill must still return a full vocab_size logit \
                 vector — an empty result means the tail was (wrongly) skipped on the LAST \
                 chunk too"
            );
            eprintln!(
                "emit_logits skip-correctness: argmax_ref={}, argmax_chunked={}, tokens={}",
                argmax_f32(ref_last),
                argmax_f32(&last_logits),
                tokens.len()
            );
            assert_eq!(
                argmax_f32(&last_logits),
                argmax_f32(ref_last),
                "argmax mismatch between chunked (tail-skipping) prefill and the \
                 all-positions reference's final-position row"
            );

            // The session cursor must have advanced through every chunk, including the
            // intermediate ones whose terminal tail was skipped.
            assert_eq!(state.session.kv_cache.seq_len, tokens.len());
            assert_eq!(state.session.position, tokens.len());
        }

        #[cfg(all(target_os = "macos", feature = "metal-gpu"))]
        #[test]
        fn metal_qwen35_prefill_all_logits_long_prompt_no_longer_panics() {
            // Regression gate: forward_prefill_all_logits must NOT panic when
            // n > max_prefill and LoRA is inactive. Old code panicked; new code
            // chunks the request and concatenates per-chunk all-position logits.
            let model_dir =
                std::path::PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| ".".into()))
                    .join(".lattice/models/qwen3.5-0.8b");
            if !model_dir.join("model.safetensors").exists()
                || !model_dir.join("config.json").exists()
                || !model_dir.join("tokenizer.json").exists()
            {
                eprintln!(
                    "skipping all-logits long-prompt test: model files missing at {}",
                    model_dir.display()
                );
                return;
            }

            let Some(device) = Device::system_default() else {
                eprintln!("skipping all-logits long-prompt test: no Metal device");
                return;
            };
            let _ = device;

            let model = crate::model::qwen35::Qwen35Model::from_safetensors(&model_dir)
                .expect("load qwen3.5-0.8b");
            let mut state = MetalQwen35State::new(model.weights(), model.config(), 1024)
                .expect("construct Metal qwen3.5-0.8b state");

            let tokens = long_real_text_tokens(model.tokenizer());
            assert!(tokens.len() > state.session.max_prefill);

            // Must not panic; returns n * vocab_size f32 values.
            state.reset_state();
            let flat = state.forward_prefill_all_logits(&tokens);
            assert_eq!(
                flat.len(),
                tokens.len() * model.config().vocab_size,
                "all-logits output length must be n * vocab_size"
            );

            // Final row of all-logits must agree with token-by-token final logits.
            let vocab = model.config().vocab_size;
            let final_row = &flat[(tokens.len() - 1) * vocab..tokens.len() * vocab];

            state.reset_state();
            let mut step_logits = Vec::new();
            for (pos, &tok) in tokens.iter().enumerate() {
                step_logits = state.forward_step(tok, pos);
            }

            let max_abs_diff = step_logits
                .iter()
                .zip(final_row.iter())
                .map(|(a, b)| (a - b).abs())
                .fold(0.0_f32, f32::max);

            eprintln!(
                "all-logits final-row parity: max_abs_diff={max_abs_diff:.6}, \
                 argmax_step={}, argmax_all_logits_final={}",
                argmax_f32(&step_logits),
                argmax_f32(final_row)
            );

            assert!(
                max_abs_diff < 1e-2,
                "all-logits final row diverged from step loop: max_abs_diff={max_abs_diff}"
            );
            assert_eq!(
                argmax_f32(&step_logits),
                argmax_f32(final_row),
                "argmax mismatch between step loop and all-logits final row"
            );
        }

