        /// Gate 2: B-vs-B self-consistency.  Running forward_prefill (chunked GDN path, default ON)
        /// 8 times on the same prompt must produce logits that agree within max_abs_diff < 1e-3 between
        /// consecutive runs.  Tests that the chunked kernels are deterministic under back-to-back calls.
        #[cfg(all(target_os = "macos", feature = "metal-gpu"))]
        #[test]
        fn gdn_chunked_b_vs_b_self_consistency() {
            let model_dir =
                std::path::PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| ".".into()))
                    .join(".lattice/models/qwen3.5-0.8b");
            if !model_dir.join("model.safetensors").exists() {
                eprintln!("skipping: model missing");
                return;
            }
            let model = crate::model::qwen35::Qwen35Model::from_safetensors(&model_dir)
                .expect("load qwen3.5-0.8b");
            let Some(_device) = Device::system_default() else {
                eprintln!("skipping: no Metal device");
                return;
            };
            let _gpu = gpu_test_lock();
            let mut state = MetalQwen35State::new(model.weights(), model.config(), 1024)
                .expect("construct Metal state");
            let tokens = long_real_text_tokens(model.tokenizer());

            let mut runs: Vec<Vec<f32>> = Vec::new();
            for i in 0..8usize {
                state.reset_state();
                let logits = state.forward_prefill(&tokens);
                eprintln!("B-vs-B run {}: argmax={}", i, argmax_f32(&logits));
                runs.push(logits);
            }

            let mut max_overall = 0.0f32;
            for (pair_idx, pair) in runs.windows(2).enumerate() {
                let diff = pair[0]
                    .iter()
                    .zip(pair[1].iter())
                    .map(|(a, b)| (a - b).abs())
                    .fold(0.0f32, f32::max);
                eprintln!(
                    "B-vs-B runs {pair_idx}..{}: max_abs_diff={diff:.6}",
                    pair_idx + 1
                );
                max_overall = max_overall.max(diff);
                assert!(
                    diff < 1e-3,
                    "B-vs-B self-consistency FAIL: runs {pair_idx} and {} differ by {diff:.6} (> 1e-3)",
                    pair_idx + 1
                );
            }
            eprintln!("B-vs-B gate PASS: max_abs_diff across all pairs = {max_overall:.6}");
        }

        /// Gate 3: Chunked-vs-serial GDN state diff.  After running the chunked prefill path the
        /// final S matrices in `gdn_gpu_s_matrices` must match what the serial token-by-token path
        /// produces, within max_rel_diff < 1e-3.
        #[cfg(all(target_os = "macos", feature = "metal-gpu"))]
        #[test]
        fn gdn_chunked_state_vs_serial_state_diff() {
            let model_dir =
                std::path::PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| ".".into()))
                    .join(".lattice/models/qwen3.5-0.8b");
            if !model_dir.join("model.safetensors").exists() {
                eprintln!("skipping: model missing");
                return;
            }
            let model = crate::model::qwen35::Qwen35Model::from_safetensors(&model_dir)
                .expect("load qwen3.5-0.8b");
            let Some(_device) = Device::system_default() else {
                eprintln!("skipping: no Metal device");
                return;
            };
            let _gpu = gpu_test_lock();
            use crate::speculative::MtpTargetVerifier as _;
            let mut state = MetalQwen35State::new(model.weights(), model.config(), 1024)
                .expect("construct Metal state");
            let tokens = long_real_text_tokens(model.tokenizer());

            // Magnitude-aware diff of a chunked snapshot against a serial snapshot.
            // The chunked scan accumulates via chunk-GEMMs in a different float order than the
            // serial recurrence, so bit-exactness is impossible; we bound the absolute error and
            // a relative error restricted to non-negligible state elements (a raw relative metric
            // explodes on near-zero entries with no bearing on correctness).
            let diff = |chunked_snap: &crate::attention::gdn::GdnSnapshot,
                        serial_snap: &crate::attention::gdn::GdnSnapshot|
             -> (f32, f32, usize) {
                assert_eq!(
                    chunked_snap.len(),
                    serial_snap.len(),
                    "snapshot layer count mismatch"
                );
                let (mut max_abs, mut max_rel_sig, mut over) = (0.0f32, 0.0f32, 0usize);
                for ((s_chunked, _), (s_serial, _)) in chunked_snap.iter().zip(serial_snap.iter()) {
                    assert_eq!(
                        s_chunked.len(),
                        s_serial.len(),
                        "S matrix element count mismatch"
                    );
                    for (sc, ss) in s_chunked.iter().zip(s_serial.iter()) {
                        let abs_diff = (sc - ss).abs();
                        max_abs = max_abs.max(abs_diff);
                        if ss.abs() > 1e-2f32 {
                            let rel = abs_diff / ss.abs();
                            max_rel_sig = max_rel_sig.max(rel);
                            if rel >= 5e-2f32 {
                                over += 1;
                            }
                        }
                    }
                }
                (max_abs, max_rel_sig, over)
            };

            // The chunked GDN scan is itself deterministic — gdn_chunked_b_vs_b_self_consistency and
            // the race-localization probe both show chunked-vs-chunked state diff = 0.0 across many
            // runs.  The only remaining nondeterminism is the pre-existing batched/decode attention
            // race (ADR-065), which perturbs the residual stream on ~1-in-N runs.  GPU access is
            // serialized via gpu_test_lock() so that race is not amplified by device contention, but
            // it can still occasionally perturb the *serial* forward_step reference by ~1e-3.
            //
            // So the chunked snapshot — the path actually under test — is computed exactly ONCE
            // outside the retry loop.  The loop re-samples only the serial reference and keeps the
            // best comparison.  A flaky chunked attempt can therefore never be masked by best-of-N:
            // if the single chunked snapshot were wrong, every attempt would diverge and the gate
            // would fail.  We only tolerate retries cleaning the known-racy serial reference.
            const MAX_ABS_THRESHOLD: f32 = 5e-3;
            const MAX_REL_SIG_THRESHOLD: f32 = 5e-2;

            // Chunked path (ON via per-instance flag) — computed once, held fixed.
            state.use_gdn_chunked = true;
            state.reset_state();
            let _ = state.forward_prefill(&tokens);
            let chunked_snap = state.snapshot_gdn_states();

            let mut best: Option<(f32, f32, usize)> = None;
            for attempt in 0..3 {
                // Serial token-by-token reference (chunked OFF via per-instance flag).
                state.use_gdn_chunked = false;
                state.reset_state();
                for (pos, &tok) in tokens.iter().enumerate() {
                    let _ = state.forward_step(tok, pos);
                }
                let serial_snap = state.snapshot_gdn_states();
                state.use_gdn_chunked = true;

                let (max_abs, max_rel_sig, over) = diff(&chunked_snap, &serial_snap);
                eprintln!(
                    "State diff attempt {attempt}: max_abs_diff={max_abs:.6}, \
                     max_rel_diff(|S|>1e-2)={max_rel_sig:.6}, sig_elems_over_5e-2={over}"
                );
                let better = best.map(|(a, _, _)| max_abs < a).unwrap_or(true);
                if better {
                    best = Some((max_abs, max_rel_sig, over));
                }
                if max_abs < MAX_ABS_THRESHOLD && max_rel_sig < MAX_REL_SIG_THRESHOLD {
                    break;
                }
            }
            let (max_abs_diff, max_rel_sig, over) = best.expect("at least one attempt");
            eprintln!(
                "State diff (best of 3): max_abs_diff={max_abs_diff:.6}, \
                 max_rel_diff(|S|>1e-2)={max_rel_sig:.6}, sig_elems_over_5e-2={over}"
            );
            assert!(
                max_abs_diff < MAX_ABS_THRESHOLD && max_rel_sig < MAX_REL_SIG_THRESHOLD,
                "GDN state S diverges (chunked vs serial): max_abs_diff={max_abs_diff:.6} \
                 (threshold {MAX_ABS_THRESHOLD:.0e}), max_rel_diff(|S|>1e-2)={max_rel_sig:.6} \
                 (threshold {MAX_REL_SIG_THRESHOLD:.0e})"
            );
        }

        /// Boundary-sweep parity gate: chunked-GDN `forward_prefill` vs serial `forward_prefill`
        /// must produce matching argmax at EVERY position for prompts that straddle the C=32 chunk
        /// boundary and the 512 max_prefill boundary.
        ///
        /// Both paths are selected via `state.use_gdn_chunked` (no process-env mutation), so there
        /// are no setenv races. GPU access is additionally serialized via `gpu_test_lock()` so the
        /// pre-existing ADR-065 attention race is not amplified by concurrent device contention,
        /// and the deterministic chunked logits are computed once per length while only the serial
        /// reference is retried — a flaky chunked attempt cannot be masked by best-of-N.
        ///
        /// This is a LOCAL/manual gate: `cargo test -p lattice-inference gdn_chunked
        /// --features "f16,metal-gpu" -- --nocapture` with the model present.  The production
        /// cross-framework gate is `e2e-parity.yml`, which runs HF-vs-lattice greedy-token parity
        /// on macOS and includes an 816-token oversize prompt that forces the >512 chunked path.
        #[cfg(all(target_os = "macos", feature = "metal-gpu"))]
        #[test]
        fn gdn_chunked_prefill_vs_serial_prefill_logit_parity() {
            let model_dir =
                std::path::PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| ".".into()))
                    .join(".lattice/models/qwen3.5-0.8b");
            if !model_dir.join("model.safetensors").exists() {
                eprintln!(
                    "skipping gdn_chunked_prefill_vs_serial_prefill_logit_parity: model missing"
                );
                return;
            }
            let model = crate::model::qwen35::Qwen35Model::from_safetensors(&model_dir)
                .expect("load qwen3.5-0.8b");
            let Some(_device) = Device::system_default() else {
                eprintln!("skipping: no Metal device");
                return;
            };
            let _gpu = gpu_test_lock();

            let max_ctx = 1024usize;
            let mut state = MetalQwen35State::new(model.weights(), model.config(), max_ctx)
                .expect("construct Metal state");
            let vocab = model.config().vocab_size;

            // Token source: a long real-text prompt; truncate to each sweep length below.
            let base_tokens = long_real_text_tokens(model.tokenizer());

            // Sweep lengths chosen to straddle C=32 chunk boundaries and the 512 max_prefill
            // boundary.  Skip lengths that exceed the model's max context.
            let sweep_lengths: &[usize] = &[1, 31, 32, 33, 64, 511, 512, 513, 1009];

            // Evidence table: (len, all-position max_abs_diff, argmax flip count)
            let mut evidence: Vec<(usize, f32, usize)> = Vec::new();
            let mut any_flip = false;

            // The chunked scan is deterministic (gdn_chunked_b_vs_b_self_consistency), but
            // chunked-vs-serial all-position value drift grows with prompt length even after
            // best-of-N discards the ADR-065 serial-race outliers: best-of-5 max_abs_diff
            // reaches ~4.8e-2 at n=1009 and crosses the old 1e-2 bound at n=511/512/513
            // (#534). The value bound below is a drift sentinel, not the correctness gate —
            // the argmax-flip assertion after the sweep is the hard safety check. Tighten
            // this bound if a future kernel change brings chunked-vs-serial drift back down.
            const MAX_ABS_BOUND: f32 = 6.5e-2;
            const ATTEMPTS: usize = 5;

            for &n in sweep_lengths {
                if n > max_ctx {
                    eprintln!("  len={n}: skipped (exceeds max_ctx={max_ctx})");
                    continue;
                }
                // Pad base_tokens with repeated token 1 if needed.
                let tokens: Vec<u32> = if n <= base_tokens.len() {
                    base_tokens[..n].to_vec()
                } else {
                    let mut v = base_tokens.clone();
                    v.resize(n, 1u32);
                    v
                };

                // Chunked path (chunked ON) — the path under test.  Deterministic
                // (gdn_chunked_b_vs_b_self_consistency), so compute it exactly ONCE and hold it
                // fixed; the best-of-N below re-samples only the serial reference.  This is what
                // makes the gate sound: a flaky chunked result would diverge on every attempt and
                // fail the gate, never get masked by a lucky retry.
                state.use_gdn_chunked = true;
                state.reset_state();
                let chunked_all = state.forward_prefill_all_logits(&tokens);
                assert_eq!(
                    chunked_all.len(),
                    n * vocab,
                    "chunked all_logits len mismatch at n={n}"
                );

                // Best-of-N: the serial reference is perturbed by the ADR-065 race on a minority
                // of runs.  Keep the attempt with the smallest max_abs (and its flip count); a
                // single clean comparison proves the chunked algorithm correct, so stop early once
                // one attempt is within bound and flip-free.  Mirrors
                // gdn_chunked_state_vs_serial_state_diff.
                let mut best_max_abs = f32::MAX;
                let mut best_flips = usize::MAX;
                for _ in 0..ATTEMPTS {
                    // Serial path (chunked OFF): per-position logits via all_logits.
                    state.use_gdn_chunked = false;
                    state.reset_state();
                    let serial_all = state.forward_prefill_all_logits(&tokens);
                    assert_eq!(
                        serial_all.len(),
                        n * vocab,
                        "serial all_logits len mismatch at n={n}"
                    );

                    // Compare at every position.
                    let mut max_abs = 0.0f32;
                    let mut flips = 0usize;
                    for pos in 0..n {
                        let s = &serial_all[pos * vocab..(pos + 1) * vocab];
                        let c = &chunked_all[pos * vocab..(pos + 1) * vocab];
                        let pos_max = s
                            .iter()
                            .zip(c.iter())
                            .map(|(a, b)| (a - b).abs())
                            .fold(0.0f32, f32::max);
                        max_abs = max_abs.max(pos_max);
                        if argmax_f32(s) != argmax_f32(c) {
                            flips += 1;
                        }
                    }

                    if max_abs < best_max_abs {
                        best_max_abs = max_abs;
                        best_flips = flips;
                    }
                    if best_max_abs < MAX_ABS_BOUND && best_flips == 0 {
                        break;
                    }
                }

                eprintln!(
                    "  len={n:4}: best-of-{ATTEMPTS} all-pos max_abs_diff={best_max_abs:.2e}  argmax_flips={best_flips}"
                );
                evidence.push((n, best_max_abs, best_flips));
                if best_flips > 0 {
                    any_flip = true;
                }
            }

            // Restore default after sweep.
            state.use_gdn_chunked = true;

            eprintln!("Evidence table (boundary sweep, per-instance flag, no env mutation):");
            eprintln!("  len | all-pos max_abs_diff | argmax_flips");
            for (n, d, f) in &evidence {
                eprintln!("  {n:4} | {d:.2e}             | {f}");
            }

            // Assert no argmax flips across all lengths and positions.
            assert!(
                !any_flip,
                "argmax flips detected across boundary sweep — default-on is unsafe. \
                 Evidence: {evidence:?}"
            );

            // Assert all-position max_abs_diff stays within the evidence-based drift sentinel.
            for (n, max_abs, _) in &evidence {
                assert!(
                    *max_abs < MAX_ABS_BOUND,
                    "len={n}: all-position max_abs_diff={max_abs:.2e} exceeds #534 drift sentinel {MAX_ABS_BOUND:.2e}"
                );
            }
        }

        /// Localization probe: run the SERIAL token-by-token path twice and diff the final GDN
        /// state.  If the serial reference is itself nondeterministic, the chunked-vs-serial state
        /// diff cannot isolate the chunked kernels — the race lives in shared input producers
        /// (gdn_qkv / hidden / in_proj), not the chunked scan.  Also runs chunked twice for
        /// comparison.  Diagnostic only — does not assert.
        #[cfg(all(target_os = "macos", feature = "metal-gpu"))]
        #[test]
        fn gdn_chunked_race_localization_probe() {
            let model_dir =
                std::path::PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| ".".into()))
                    .join(".lattice/models/qwen3.5-0.8b");
            if !model_dir.join("model.safetensors").exists() {
                eprintln!("skipping: model missing");
                return;
            }
            let model = crate::model::qwen35::Qwen35Model::from_safetensors(&model_dir)
                .expect("load qwen3.5-0.8b");
            let Some(_device) = Device::system_default() else {
                eprintln!("skipping: no Metal device");
                return;
            };
            let _gpu = gpu_test_lock();
            use crate::speculative::MtpTargetVerifier as _;
            let mut state = MetalQwen35State::new(model.weights(), model.config(), 1024)
                .expect("construct Metal state");
            let tokens = long_real_text_tokens(model.tokenizer());

            let snap_state = |st: &MetalQwen35State| -> Vec<f32> {
                st.snapshot_gdn_states()
                    .into_iter()
                    .flat_map(|(s, _conv)| s)
                    .collect()
            };
            let max_diff = |a: &[f32], b: &[f32]| -> f32 {
                a.iter()
                    .zip(b.iter())
                    .map(|(x, y)| (x - y).abs())
                    .fold(0.0f32, f32::max)
            };

            // Serial path, twice (chunked OFF via per-instance flag).
            state.use_gdn_chunked = false;
            state.reset_state();
            for (pos, &tok) in tokens.iter().enumerate() {
                let _ = state.forward_step(tok, pos);
            }
            let serial_a = snap_state(&state);
            state.reset_state();
            for (pos, &tok) in tokens.iter().enumerate() {
                let _ = state.forward_step(tok, pos);
            }
            let serial_b = snap_state(&state);

            // Batched prefill with chunked GDN OFF (batched producers + serial GDN consumer), twice.
            state.use_gdn_chunked = false;
            state.reset_state();
            let _ = state.forward_prefill(&tokens);
            let prefill_nochunk_a = snap_state(&state);
            state.reset_state();
            let _ = state.forward_prefill(&tokens);
            let prefill_nochunk_b = snap_state(&state);

            // Chunked path, twice (chunked ON via per-instance flag).
            state.use_gdn_chunked = true;
            state.reset_state();
            let _ = state.forward_prefill(&tokens);
            let chunked_a = snap_state(&state);
            state.reset_state();
            let _ = state.forward_prefill(&tokens);
            let chunked_b = snap_state(&state);

            eprintln!(
                "RACE-LOCALIZATION: serial-vs-serial (forward_step) state max_abs_diff = {:.6}",
                max_diff(&serial_a, &serial_b)
            );
            eprintln!(
                "RACE-LOCALIZATION: prefill-NOCHUNK-vs-NOCHUNK (batched producer + serial GDN) max_abs_diff = {:.6}",
                max_diff(&prefill_nochunk_a, &prefill_nochunk_b)
            );
            eprintln!(
                "RACE-LOCALIZATION: chunked-vs-chunked state max_abs_diff = {:.6}",
                max_diff(&chunked_a, &chunked_b)
            );
            eprintln!(
                "RACE-LOCALIZATION: chunked-vs-serial state max_abs_diff = {:.6}",
                max_diff(&chunked_a, &serial_a)
            );
        }

        // -------------------------------------------------------------------
        // Q8_0 non-finite input guard — mutation-sensitive (Finding 1, PR #452)
        //
        // IEEE 754: `NaN > x` is always false, so a fold-max over a block
        // containing NaN leaves `amax` unchanged, and the NaN element is
        // silently cast to 0 by the `clamp`, producing a plausible-looking
        // packed buffer with a wrong entry and no error.
        //
        // Mutation sensitivity: removing the `if !v.is_finite()` guard in
        // `quantize_row_q8_0` converts both Err returns to Ok, making
        // `result.is_err()` false and failing both assertions.
        // -------------------------------------------------------------------

        #[test]
        fn test_quantize_row_q8_0_rejects_nan() {
            // A block with one NaN must return Err, not silently encode it as 0.
            let mut vals = vec![1.0f32; 32];
            vals[5] = f32::NAN;
            let result = quantize_row_q8_0(&vals);
            assert!(result.is_err(), "NaN in Q8_0 weight block must return Err");
        }

        #[test]
        fn test_quantize_row_q8_0_rejects_inf() {
            // A block with +inf must return Err; is_finite() rejects NaN, +inf, and -inf.
            let mut vals = vec![1.0f32; 32];
            vals[15] = f32::INFINITY;
            let result = quantize_row_q8_0(&vals);
            assert!(result.is_err(), "+inf in Q8_0 weight block must return Err");
        }

        // ---------------------------------------------------------------------
        // Cross-turn KV prefix cache (#462): Metal integration tests.
        //
        // `single_char_vocab_tokenizer` gives a 32-token, merge-free vocab
        // (one token per ASCII letter) so growing a conversation by string
        // concatenation is guaranteed to grow the token sequence by an exact
        // append — no re-tokenization boundary can shift earlier tokens,
        // which keeps these tests focused on the cache logic itself rather
        // than on tokenizer edge cases.
        // ---------------------------------------------------------------------

        fn cross_turn_test_gen_cfg(seed: u64, max_new_tokens: usize) -> GenerateConfig {
            GenerateConfig {
                max_new_tokens,
                temperature: 0.0,
                top_k: 1,
                top_p: 1.0,
                repetition_penalty: 1.0,
                seed: Some(seed),
                stop_token_ids: vec![],
                enable_thinking: false,
                enable_mtp: Some(false),
                grammar: None,
                stop_strings: vec![],
                reasoning_budget: None,
                logprobs: None,
            }
        }

        /// The correctness gate for #462: a growing multi-turn conversation run
        /// through `generate_streaming_with_prefix_cache` on one long-lived state
        /// must produce byte-identical token IDs, turn by turn, to running each
        /// turn's full accumulated prompt through plain `generate_streaming` on a
        /// fresh state (i.e. the pre-#462 "re-prefill everything every turn"
        /// behavior). If cross-turn KV/GDN reuse ever perturbs a single sampled
        /// token, this test goes red.
        #[test]
        fn cross_turn_cache_multiturn_token_identity_matches_full_reprefill() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            // Keep EOS unreachable so every turn generates its full budget,
            // guaranteeing the conversation keeps growing turn over turn.
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut cached_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");

            let user_turns = ["a", "bc", "d", "ef", "g"];
            let mut conversation = String::new();
            let mut saw_exact_append = false;

            for (turn_idx, user_text) in user_turns.iter().enumerate() {
                conversation.push_str(user_text);
                let gen_cfg = cross_turn_test_gen_cfg(42, 3);

                let mut cached_delta_calls = 0u32;
                let cached_out = cached_state
                    .generate_streaming_with_prefix_cache(
                        slot_id,
                        &conversation,
                        &tokenizer,
                        &gen_cfg,
                        |_delta, _id| {
                            cached_delta_calls += 1;
                            true
                        },
                    )
                    .expect("cache-aware generation must not error on a valid conversation");

                // Independent, from-scratch reference: a brand new state, full
                // re-prefill of the entire accumulated conversation so far —
                // exactly the behavior cross-turn reuse must reproduce.
                let mut reference_state =
                    MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
                let reference_gen_cfg = cross_turn_test_gen_cfg(42, 3);
                let reference_out = reference_state
                    .generate_streaming(
                        &conversation,
                        &tokenizer,
                        &reference_gen_cfg,
                        |_delta, _id| true,
                    )
                    .expect("no grammar configured; must not fail closed");

                assert_eq!(
                    cached_out.output.token_ids, reference_out.token_ids,
                    "turn {turn_idx}: cache-aware token IDs must match full re-prefill \
                     exactly (conversation so far: {conversation:?})"
                );
                assert_eq!(
                    cached_out.output.text, reference_out.text,
                    "turn {turn_idx}: cache-aware decoded text must match full re-prefill"
                );
                assert_eq!(
                    cached_out.output.stop_reason, reference_out.stop_reason,
                    "turn {turn_idx}: stop reason must match full re-prefill"
                );

                if matches!(
                    cached_out.cache.mode,
                    crate::kv_cache::PrefixReuseMode::ExactAppend
                ) {
                    saw_exact_append = true;
                    assert!(
                        cached_out.cache.reused_tokens > 0,
                        "turn {turn_idx}: ExactAppend must report a nonzero reused prefix"
                    );
                }

                // Grow the conversation with the (validated-identical) reply so
                // the next turn's prompt is a real append onto this one.
                conversation.push_str(&cached_out.output.text);
            }

            assert!(
                saw_exact_append,
                "at least one later turn must actually exercise ExactAppend reuse — \
                 otherwise this test only proves the FullRefill fallback path works"
            );
        }

        /// Sibling of the above, but exercised through the `ChatMessage`-based
        /// `chat_completion_streaming_with_prefix_cache` wrapper rather than raw
        /// prompt strings — this is the exact entry point `chat_metal`'s
        /// interactive REPL calls (#462), so it must reproduce plain
        /// `chat_completion_streaming`'s output turn-for-turn on a growing
        /// conversation history, including `format_chat_template`'s ChatML
        /// framing and `<|im_end|>` stop-token handling.
        #[test]
        fn cross_turn_cache_chat_completion_matches_full_reprefill() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            // Keep EOS unreachable so every turn generates its full budget,
            // guaranteeing the history keeps growing turn over turn (mirrors the
            // raw-prompt sibling test above).
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            // max_cache_len=128 = this fixture's max_position_embeddings ceiling;
            // four short turns of ChatML-formatted history (role words + content)
            // stay well under it (~70 tokens at the last turn).
            let mut cached_state =
                MetalQwen35State::new(&weights, &cfg, 128).expect("tiny hybrid fixture");

            let user_turns = ["a", "bc", "d", "ef"];
            let mut history: Vec<ChatMessage> = vec![ChatMessage::system("")];
            let mut saw_exact_append = false;

            for (turn_idx, user_text) in user_turns.iter().enumerate() {
                history.push(ChatMessage::user(*user_text));
                let gen_cfg = cross_turn_test_gen_cfg(42, 2);

                let cached_out = cached_state
                    .chat_completion_streaming_with_prefix_cache(
                        slot_id,
                        &history,
                        &tokenizer,
                        &gen_cfg,
                        |_delta, _id| true,
                    )
                    .expect("cache-aware chat completion must not error on a valid history");

                // Independent, from-scratch reference: a brand new state, the
                // plain (non-cache) chat_completion_streaming path over the same
                // history — exactly chat_metal's pre-#462 behavior (reset_state +
                // full re-prefill of the whole ChatML-formatted history every turn).
                let mut reference_state =
                    MetalQwen35State::new(&weights, &cfg, 128).expect("tiny hybrid fixture");
                let reference_gen_cfg = cross_turn_test_gen_cfg(42, 2);
                let reference_out = reference_state
                    .chat_completion_streaming(
                        &history,
                        &tokenizer,
                        &reference_gen_cfg,
                        |_delta, _id| true,
                    )
                    .expect("reference chat completion must not error on a valid history");

                assert_eq!(
                    cached_out.output.message.content, reference_out.message.content,
                    "turn {turn_idx}: cache-aware chat completion must match full re-prefill exactly"
                );
                assert_eq!(
                    cached_out.output.prompt_tokens, reference_out.prompt_tokens,
                    "turn {turn_idx}: prompt_tokens must match full re-prefill"
                );
                assert_eq!(
                    cached_out.output.completion_tokens, reference_out.completion_tokens,
                    "turn {turn_idx}: completion_tokens must match full re-prefill"
                );

                if matches!(
                    cached_out.cache.mode,
                    crate::kv_cache::PrefixReuseMode::ExactAppend
                ) {
                    saw_exact_append = true;
                    assert!(
                        cached_out.cache.reused_tokens > 0,
                        "turn {turn_idx}: ExactAppend must report a nonzero reused prefix"
                    );
                }

                // Grow history with the (validated-identical) reply so the next
                // turn's prompt is a real append onto this one, matching real
                // REPL usage in chat_metal.
                history.push(cached_out.output.message.clone());
            }

            assert!(
                saw_exact_append,
                "at least one later turn must actually exercise ExactAppend reuse through the \
                 ChatMessage-based wrapper — otherwise this test only proves the FullRefill \
                 path works"
            );
        }

        /// The correctness gate for #590: editing an earlier turn (a prompt
        /// that diverges from the cached history mid-way, at or after a
        /// retained sparse GDN checkpoint boundary) must take the
        /// `ReplayFromCheckpoint` path — GDN state restored from the ring
        /// snapshot, KV rows below the boundary reused in place, divergent
        /// suffix prefilled forward — and produce byte-identical token IDs
        /// to running the edited conversation as a full re-prefill on a
        /// fresh state. If checkpoint replay ever perturbs a single sampled
        /// token, this test goes red.
        ///
        /// Mutation sensitivity: reverting the #590 restore arm to its old
        /// fail-closed error makes the edited turn error out (the plan
        /// selects `ReplayFromCheckpoint`, which the old arm rejected);
        /// reverting the ring carry in `save_cross_turn_prefix` leaves the
        /// plan at `FullRefill` and the mode assertion fails; disabling the
        /// carry-time `checkpoint_survives_save` pruning lets the stale
        /// turn-2 boundary survive the edit and the turn-5 probe's
        /// `checkpoint_len == l1_len` assertion fails.
        #[test]
        fn cross_turn_replay_from_checkpoint_matches_full_reprefill() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut cached_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(42, 3);

            // Turn 1: establish the entry whose boundary becomes the ring
            // checkpoint after turn 2's save.
            let turn1_prompt = "abc".to_string();
            let turn1 = cached_state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &turn1_prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("turn 1 must succeed");
            let history_through_turn1 = format!("{turn1_prompt}{}", turn1.output.text);

            // Turn 2: exact append. Its save must promote turn 1's boundary
            // snapshot into the checkpoint ring.
            let turn2_prompt = format!("{history_through_turn1}de");
            let turn2 = cached_state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &turn2_prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("turn 2 must succeed");
            assert_eq!(
                turn2.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "turn 2 must exercise ExactAppend so its save carries turn 1's boundary \
                 into the checkpoint ring"
            );

            // Turn 3: second exact append — its save carries turn 1's
            // boundary forward AND promotes turn 2's boundary, so the ring
            // now holds two checkpoints at different depths.
            let turn2_full = format!("{turn2_prompt}{}", turn2.output.text);
            let turn3_prompt = format!("{turn2_full}gh");
            let turn3 = cached_state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &turn3_prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("turn 3 must succeed");
            assert_eq!(
                turn3.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "turn 3 must exercise ExactAppend so the ring holds both the \
                 turn-1 and turn-2 boundaries"
            );
            // Single-char ASCII vocab: 1 byte == 1 token, so boundary
            // lengths are plain byte lengths of the transcript strings.
            let l1_len = history_through_turn1.len();
            let l2_len = turn2_full.len();

            // Turn 4: EDIT turn 2 — same history through turn 1, different
            // user text after it. The shared prefix with the cached entry
            // ends where "de" was; the deepest eligible ring checkpoint at
            // or below that divergence is turn 1's boundary (turn 2's is
            // deeper than the divergence and must be ineligible), so the
            // planner must select ReplayFromCheckpoint at exactly `l1_len`.
            let edited_prompt = format!("{history_through_turn1}wxyz");
            let edited = cached_state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &edited_prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("edited-history turn must succeed");
            assert_eq!(
                edited.cache.mode,
                crate::kv_cache::PrefixReuseMode::ReplayFromCheckpoint {
                    checkpoint_len: l1_len
                },
                "editing turn 2 must replay from turn 1's boundary checkpoint"
            );
            assert!(
                edited.cache.reused_tokens > 0,
                "replay must report a nonzero reused prefix"
            );

            // Reference: the edited conversation as a full re-prefill on a
            // brand-new state — exactly the behavior replay must reproduce.
            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_gen_cfg = cross_turn_test_gen_cfg(42, 3);
            let reference_out = reference_state
                .generate_streaming(&edited_prompt, &tokenizer, &reference_gen_cfg, |_, _| true)
                .expect("reference re-prefill generate_streaming");
            assert_eq!(
                edited.output.token_ids, reference_out.token_ids,
                "replayed-from-checkpoint token IDs must match full re-prefill exactly"
            );
            assert_eq!(
                edited.output.text, reference_out.text,
                "replayed-from-checkpoint decoded text must match full re-prefill"
            );
            assert_eq!(
                edited.output.stop_reason, reference_out.stop_reason,
                "stop reason must match full re-prefill"
            );

            // Turn 5: probe that the save after the replay PRUNED the stale
            // turn-2 boundary (its history diverged) while keeping turn 1's.
            // Diverge at exactly the old turn-2 boundary depth: a stale
            // checkpoint surviving there would be the deepest eligible one,
            // the planner would pick it, and GDN state from the abandoned
            // timeline would drive generation. The correct ring holds only
            // turn 1's boundary at or below this divergence.
            let edited_full = format!("{edited_prompt}{}", edited.output.text);
            assert!(
                edited_full.len() > l2_len,
                "edited transcript must extend past the old turn-2 boundary"
            );
            // Pick a divergent continuation guaranteed to differ from the
            // generated char at the divergence point (vocab is a-z + A-F).
            let cont = edited_full.as_bytes()[l2_len];
            let div = if cont == b'A' { "BB" } else { "AA" };
            let probe_prompt = format!("{}{div}", &edited_full[..l2_len]);
            let probe = cached_state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &probe_prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("stale-checkpoint probe turn must succeed");
            assert_eq!(
                probe.cache.mode,
                crate::kv_cache::PrefixReuseMode::ReplayFromCheckpoint {
                    checkpoint_len: l1_len
                },
                "the post-replay save must prune the stale turn-2 boundary; \
                 only turn 1's checkpoint may serve this divergence"
            );
            let mut probe_reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let probe_reference = probe_reference_state
                .generate_streaming(
                    &probe_prompt,
                    &tokenizer,
                    &cross_turn_test_gen_cfg(42, 3),
                    |_, _| true,
                )
                .expect("probe reference generate_streaming");
            assert_eq!(
                probe.output.token_ids, probe_reference.token_ids,
                "probe token IDs must match full re-prefill exactly"
            );

            // A follow-up append onto the probe history must still reuse
            // cleanly.
            let followup_prompt = format!("{probe_prompt}{}h", probe.output.text);
            let followup = cached_state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &followup_prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("follow-up append after replay must succeed");
            assert_eq!(
                followup.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "the post-replay save must leave a reusable entry for a plain append"
            );
            let mut followup_reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let followup_reference = followup_reference_state
                .generate_streaming(
                    &followup_prompt,
                    &tokenizer,
                    &cross_turn_test_gen_cfg(42, 3),
                    |_, _| true,
                )
                .expect("followup reference generate_streaming");
            assert_eq!(
                followup.output.token_ids, followup_reference.token_ids,
                "post-replay append token IDs must match full re-prefill exactly"
            );
        }
        /// Prefix-mismatch invalidation: when the new prompt does not share the
        /// cached entry's history at all, the planner must fall back to
        /// `FullRefill` (never attempt to graft an unrelated suffix onto stale
        /// KV/GDN state), and the output must still be correct.
        #[test]
        fn cross_turn_cache_prefix_mismatch_falls_back_to_full_refill() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(7, 2);

            let first = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "abc",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("first turn must succeed");
            assert_eq!(
                first.cache.mode,
                crate::kv_cache::PrefixReuseMode::FullRefill,
                "an empty cache must always plan FullRefill"
            );

            // Completely different conversation: zero shared token prefix
            // with the cached entry from "abc".
            let second = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "xyz",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("divergent-prefix turn must still succeed");
            assert_eq!(
                second.cache.mode,
                crate::kv_cache::PrefixReuseMode::FullRefill,
                "a prompt sharing no prefix with the cached entry must invalidate to FullRefill"
            );

            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming("xyz", &tokenizer, &gen_cfg, |_, _| true)
                .expect("no grammar configured; must not fail closed");
            assert_eq!(
                second.output.token_ids, reference_out.token_ids,
                "after a prefix-mismatch invalidation, output must still match full re-prefill"
            );
        }

        /// `clear_cross_turn_prefix_cache` must force the next call to plan
        /// `FullRefill` even when the new prompt would otherwise be a valid
        /// `ExactAppend` continuation of the (now-cleared) entry.
        #[test]
        fn cross_turn_cache_clear_forces_full_refill_next_call() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(3, 2);

            let first = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("first turn must succeed");
            let mut conversation = "ab".to_string();
            conversation.push_str(&first.output.text);

            state.clear_cross_turn_prefix_cache();

            let second = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &conversation,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("second turn after clear must succeed");
            assert_eq!(
                second.cache.mode,
                crate::kv_cache::PrefixReuseMode::FullRefill,
                "a cleared cache slot must never be treated as a valid cached entry"
            );
        }

        // -------------------------------------------------------------------
        // #516 remediation — regression coverage for
        // findings 1/2/3/4.
        // -------------------------------------------------------------------

        /// Finding 1 (slot isolation): a divergent-prompt call on a
        /// different slot must evict the single retained entry (D1's
        /// single-live-entry cache), so a later append to the ORIGINAL
        /// slot's prefix cannot silently restore GDN state left by a
        /// different slot's generation while attention reads whatever KV
        /// rows the other slot's generation wrote.
        #[test]
        fn cross_turn_cache_slot_isolation_evicts_other_slot() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_a = crate::kv_cache::CrossTurnSlotId::new(1);
            let slot_b = crate::kv_cache::CrossTurnSlotId::new(2);
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(11, 2);

            // Save slot A.
            let first = state
                .generate_streaming_with_prefix_cache(slot_a, "ab", &tokenizer, &gen_cfg, |_, _| {
                    true
                })
                .expect("slot A first turn must succeed");
            let mut conv_a = "ab".to_string();
            conv_a.push_str(&first.output.text);

            // Divergent-prompt call on slot B: under D1, `insert` replaces
            // whatever is retained regardless of slot, so this evicts A's
            // entry and retains B's.
            state
                .generate_streaming_with_prefix_cache(
                    slot_b,
                    "xyz",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("slot B turn must succeed");

            // Append-only continuation of A's prefix, issued on slot A
            // AFTER B evicted the single retained entry: must NOT
            // ExactAppend (there is no A entry left to restore from).
            let second = state
                .generate_streaming_with_prefix_cache(
                    slot_a,
                    &conv_a,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("slot A second turn must succeed");
            assert_eq!(
                second.cache.reused_tokens, 0,
                "slot A must not reuse GDN/KV state left by slot B's generation"
            );
            assert_ne!(
                second.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "a different-slot eviction must force a FullRefill, never ExactAppend"
            );

            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming(&conv_a, &tokenizer, &gen_cfg, |_, _| true)
                .expect("no grammar configured; must not fail closed");
            assert_eq!(
                second.output.token_ids, reference_out.token_ids,
                "after cross-slot eviction, output must still match full re-prefill"
            );
        }

        /// Finding 2, plain-path leg (D3): interleaving a plain
        /// `generate_streaming` call (which goes through `reset_state`)
        /// between two cache-aware calls must invalidate the retained
        /// entry — the plain path overwrites live KV/GDN state without
        /// ever calling `save_cross_turn_prefix`.
        ///
        /// Mutation sensitivity: reverting D3 (removing
        /// `self.cross_turn_prefix_cache.clear()` from `reset_state`) makes
        /// this test fail, because the stale entry would still report
        /// `ExactAppend` against state the plain path already overwrote.
        #[test]
        fn cross_turn_cache_interleaved_plain_path_invalidates() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(21, 2);

            // Save a cross-turn entry.
            let first = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("cache-aware first turn must succeed");
            let mut conversation = "ab".to_string();
            conversation.push_str(&first.output.text);

            // Plain path: a different prompt, routed through `reset_state`,
            // never touches the cross-turn cache's save path.
            let _ = state.generate_streaming("zzzzzz", &tokenizer, &gen_cfg, |_, _| true);

            // A genuine append (strictly longer than the cached entry) onto
            // the ORIGINAL prefix through the cache-aware path again: if the
            // stale entry survived, this satisfies D5's `len > shared` guard
            // too (it is NOT an exact-equal retry), so it would still look
            // like a valid ExactAppend continuation of `conversation` and
            // this test would only be sensitive to D3, not accidentally
            // masked by D5's separate guard.
            let mut appended = conversation.clone();
            appended.push('q');
            let second = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &appended,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("cache-aware second turn must succeed");
            assert_eq!(
                second.cache.reused_tokens, 0,
                "an interleaved plain generate_streaming call must invalidate the retained entry"
            );

            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming(&appended, &tokenizer, &gen_cfg, |_, _| true)
                .expect("no grammar configured; must not fail closed");
            assert_eq!(
                second.output.token_ids, reference_out.token_ids,
                "after an interleaved plain-path reset, output must still match full re-prefill"
            );
        }

        /// Finding 4 (D5): retrying the exact same prompt through the
        /// cache-aware path must not hit the empty-suffix invariant error
        /// in `forward_prefill_from` — the planner must fall back to
        /// `FullRefill` when the new prompt exactly equals the entry's
        /// represented tokens.
        ///
        /// Mutation sensitivity: reverting D5 (dropping the
        /// `new_prompt_ids.len() > shared` conjunct in
        /// `plan_prefix_reuse`) makes this test fail: the planner would
        /// again produce `ExactAppend` with `suffix_len == 0`, and
        /// `generate_streaming_with_prefix_cache` would return
        /// `Err(InferenceError::PrefixCache(..))` instead of `Ok`.
        #[test]
        fn cross_turn_cache_exact_equal_retry_full_refills() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(5, 2);

            let first = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "abc",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("first call must succeed");

            // The saved entry represents `prompt + generated tokens`, NOT
            // just the original prompt (see the `represented_token_ids`
            // construction in `generate_streaming_with_prefix_cache_inner`).
            // To actually exercise the exact-equal boundary the second call
            // must retry with THIS accumulated conversation — retrying with
            // the bare "abc" prompt again would only exercise the ordinary
            // mid-history-divergence FullRefill path (shared < represented_len),
            // never reaching the `shared == represented_len` branch this test
            // targets.
            let mut conversation = "abc".to_string();
            conversation.push_str(&first.output.text);

            let second = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &conversation,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("exact-equal prompt retry must not error");
            assert_eq!(
                second.cache.reused_tokens, 0,
                "an exact-equal prompt retry must plan FullRefill, not a zero-length ExactAppend"
            );

            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming(&conversation, &tokenizer, &gen_cfg, |_, _| true)
                .expect("no grammar configured; must not fail closed");
            assert_eq!(
                second.output.token_ids, reference_out.token_ids,
                "exact-equal prompt retry output must match full re-prefill"
            );
        }

        /// Finding 3 (D4): LoRA adapter load/unload must invalidate the
        /// retained cross-turn entry. The adapter-identity hash in
        /// `CrossTurnPrefixMetadata` is shape-based (max_rank/scale/
        /// projection count), not content-based, so two different adapters
        /// with the same shape can collide on the same `AdapterId` — the
        /// unconditional clear on load/unload is the actual correctness
        /// mechanism, not the metadata hash. Asserted directly against the
        /// cache struct (this `mod tests` is a child module of
        /// `metal_qwen35`, so the private `entry` field is visible here).
        #[test]
        fn cross_turn_cache_lora_load_unload_invalidates() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(9, 2);

            state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("save call must succeed");
            assert!(
                state.cross_turn_prefix_cache.entry.is_some(),
                "precondition: a save must actually retain an entry"
            );

            // `tiny_hybrid_fixture`'s only FullAttention layer is index 3
            // (layers 0-2 are LinearAttention/GDN); `make_valid_layer`
            // defaults to layer_idx 0, which is only valid against the
            // single-FullAttention-layer fixture other LoRA tests use.
            let mut lora_layer = make_valid_layer(512, 2);
            lora_layer.layer_idx = 3;
            state
                .load_lora_adapter(vec![lora_layer], 1.0, None)
                .expect("load_lora_adapter with a valid small fixture must succeed");
            assert!(
                state.cross_turn_prefix_cache.entry.is_none(),
                "load_lora_adapter must clear the retained cross-turn entry"
            );

            // Re-save under the loaded adapter, then unload and check
            // invalidation again.
            state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("save call under LoRA must succeed");
            assert!(
                state.cross_turn_prefix_cache.entry.is_some(),
                "precondition: a save under LoRA must actually retain an entry"
            );

            state.unload_lora_adapter();
            assert!(
                state.cross_turn_prefix_cache.entry.is_none(),
                "unload_lora_adapter must clear the retained cross-turn entry"
            );
        }

        /// D7: a public raw-forward call
        /// (`forward_step`) interleaved between two cache-aware calls on the
        /// SAME slot must invalidate the retained entry, exactly like
        /// `generate_streaming`'s `reset_state()` does for finding 2's
        /// plain-path leg (D3, `cross_turn_cache_interleaved_plain_path_invalidates`
        /// above) — `forward_step` mutates the same live KV/GDN buffers
        /// without ever routing through `reset_state` or the cache's own
        /// save path, so it is a second, independent way to leave a stale
        /// entry pointing at overwritten state.
        ///
        /// Uses a strictly-longer continuation of the ORIGINAL conversation
        /// (append one extra character) for the second call, same as D3's
        /// test: an exact-equal retry would independently trip D5's
        /// `FullRefill` guard (`cross_turn_cache_exact_equal_retry_full_refills`)
        /// and mask whether D7's clear is actually doing anything.
        ///
        /// Mutation sensitivity: reverting D7 (removing
        /// `self.cross_turn_prefix_cache.clear()` from `forward_step`) makes
        /// this test fail — see the reverse-apply evidence recorded in the
        /// PR body.
        #[test]
        fn cross_turn_cache_interleaved_raw_forward_invalidates() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(31, 2);

            // Save a cross-turn entry via the cache-aware path (slot A's
            // only slot, since `MetalCrossTurnPrefixCache` retains at most
            // one live entry across the whole state — see D1).
            let first = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("cache-aware first turn must succeed");
            let mut conversation = "ab".to_string();
            conversation.push_str(&first.output.text);
            assert!(
                state.cross_turn_prefix_cache.entry.is_some(),
                "precondition: the first cache-aware call must actually retain an entry"
            );

            // Interleave a raw public forward call on an unrelated token
            // stream. This is the exact stale path: `forward_step`
            // advances `self.session.kv_cache` / GDN state directly, bypassing
            // both `reset_state()` (D3's guard) and the cache-aware save path.
            let _ = state.forward_step(0, 0);

            // The raw call must have invalidated the retained entry outright
            // (not just left it stale) — this is what D7 adds.
            assert!(
                state.cross_turn_prefix_cache.entry.is_none(),
                "forward_step must clear the retained cross-turn entry before mutating live state"
            );

            // Strict-append continuation of the ORIGINAL slot's conversation:
            // if the entry had survived, this shape would still satisfy D5's
            // `len > shared` guard and look like a valid ExactAppend, so the
            // assertion below is genuinely exercising D7 and not being masked
            // by D5.
            let mut appended = conversation.clone();
            appended.push('q');
            let second = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &appended,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("cache-aware second turn must succeed");
            assert_eq!(
                second.cache.reused_tokens, 0,
                "an interleaved raw forward_step call must force a full refill, not a stale restore"
            );
            assert_ne!(
                second.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "a raw-forward-invalidated entry must never be restored via ExactAppend"
            );

            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming(&appended, &tokenizer, &gen_cfg, |_, _| true)
                .expect("no grammar configured; must not fail closed");
            assert_eq!(
                second.output.token_ids, reference_out.token_ids,
                "after an interleaved raw forward_step call, output must still match full re-prefill"
            );
        }

        /// #516 round-3 remediation: `set_gdn_chunked` swaps the GDN prefill
        /// algorithm, and the two scans are not bit-exact (measured logit
        /// drift up to ~2e-1 at chunk boundaries). A cache entry saved under
        /// one mode must not seed a restore whose full-refill reference would
        /// use the other mode. Flipping the mode must evict the retained
        /// entry; a no-op set must NOT (so benchmarks re-asserting the current
        /// mode keep their cache).
        #[test]
        fn cross_turn_cache_invalidated_by_gdn_mode_flip() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(13, 2);

            let first = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("cache-aware first turn must succeed");
            let mut conversation = "ab".to_string();
            conversation.push_str(&first.output.text);
            assert!(
                state.cross_turn_prefix_cache.entry.is_some(),
                "precondition: the first cache-aware call must actually retain an entry"
            );

            // Re-asserting the CURRENT mode is a no-op and must keep the entry.
            let current_mode = state.use_gdn_chunked;
            state.set_gdn_chunked(current_mode);
            assert!(
                state.cross_turn_prefix_cache.entry.is_some(),
                "setting the already-active GDN mode must not evict the cache entry"
            );

            // Flipping the mode must evict it outright.
            state.set_gdn_chunked(!current_mode);
            assert!(
                state.cross_turn_prefix_cache.entry.is_none(),
                "flipping the GDN prefill mode must clear the retained cross-turn entry"
            );

            // Strict-append continuation: if the entry had survived the flip,
            // this shape would satisfy the ExactAppend guards, so the
            // assertions below genuinely exercise the mode-flip eviction.
            let mut appended = conversation.clone();
            appended.push('q');
            let second = state
                .generate_streaming_with_prefix_cache(
                    slot_id,
                    &appended,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                )
                .expect("cache-aware second turn must succeed");
            assert_eq!(
                second.cache.reused_tokens, 0,
                "a GDN mode flip must force a full refill, not a cross-mode restore"
            );
            assert_ne!(
                second.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "an entry saved under the other GDN prefill mode must never be restored via ExactAppend"
            );
        }

        /// #462 serve-wiring correctness gate for
        /// `generate_streaming_with_prefix_cache_and_cancel`: an immediate
        /// `should_cancel` (true before any GPU work runs) must return
        /// `StopReason::Interrupt` with zero generated tokens, and must not
        /// leave live state or the retained cache entry in a shape that
        /// corrupts a later, uncancelled call on the same state — i.e. the
        /// fail-closed guarantee the doc comment on
        /// `generate_streaming_with_prefix_cache_and_cancel` promises.
        #[test]
        fn cross_turn_cache_and_cancel_immediate_leaves_state_usable() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(7, 3);

            // Turn 1: establish a normal, saved cache entry.
            let turn1 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "a",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("turn 1 must not error");
            assert!(
                turn1.output.generated_tokens > 0,
                "precondition: turn 1 must actually generate tokens"
            );

            // Turn 2: should_cancel is already true, so no GPU work for this
            // turn should ever run. Must surface as Interrupt, not an error,
            // and must not generate any tokens.
            let turn2 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || true,
                )
                .expect("an immediate cancel must not surface as an engine error");
            assert_eq!(
                turn2.output.stop_reason,
                Some(StopReason::Interrupt),
                "an immediate should_cancel=true must stop with Interrupt"
            );
            assert_eq!(
                turn2.output.generated_tokens, 0,
                "an immediate cancel must not generate any tokens"
            );

            // Turn 3: uncancelled call on the same conversation prefix as the
            // cancelled turn 2. If the cancel path had left live KV/GDN state
            // or the retained cache entry inconsistent, this would either
            // error or diverge from a from-scratch reference.
            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming("ab", &tokenizer, &gen_cfg, |_, _| true)
                .expect("reference generate_streaming must not error");

            let turn3 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("turn 3 must not error after a cancelled turn 2");
            assert_eq!(
                turn3.output.token_ids, reference_out.token_ids,
                "post-cancel generation must still match full re-prefill exactly"
            );
        }

        /// Serve-boundary correctness gate: `lattice_serve` always calls the
        /// cancel-aware prefix-cache API on the single `CrossTurnSlotId::DEFAULT`
        /// slot regardless of which logical conversation issued the request.
        /// Two interleaved conversations sharing that one slot (A1, B1, A2)
        /// must therefore behave exactly like the plain slot-isolation case
        /// above: A2's shared prefix with the retained entry (now B's) is not
        /// a match, so the planner must fall back to `FullRefill`, and the
        /// output must still be correct.
        #[test]
        fn cross_turn_cache_and_cancel_same_slot_interleave_falls_back_to_full_refill() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(23, 2);

            // A1: establish a saved entry on the DEFAULT slot.
            let a1 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("A1 must succeed");
            let mut conv_a = "ab".to_string();
            conv_a.push_str(&a1.output.text);

            // B1: an unrelated conversation on the SAME slot -- exactly what
            // `lattice_serve` produces when two different clients' requests
            // interleave through its single worker thread. Under the
            // single-entry invariant this replaces A's retained entry.
            state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "xyz",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("B1 must succeed");

            // A2: append-only continuation of A's own conversation, issued
            // right after B1 evicted the shared slot. Must miss cleanly and
            // fall back to FullRefill -- never restore B's GDN/KV state.
            let a2 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    &conv_a,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("A2 must succeed");
            assert_eq!(
                a2.cache.reused_tokens, 0,
                "A2 must not reuse state left by B1's interleaved generation"
            );
            assert_ne!(
                a2.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "same-slot interleaving must force FullRefill for A2, never ExactAppend"
            );

            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming(&conv_a, &tokenizer, &gen_cfg, |_, _| true)
                .expect("reference generate_streaming must not error");
            assert_eq!(
                a2.output.token_ids, reference_out.token_ids,
                "after same-slot interleaved eviction, A2's output must still match \
                 full re-prefill exactly -- this is the parity the plain (uncached) \
                 path already guaranteed before #462"
            );
        }

        /// Checkpoint 2 of the cancellation contract: a `should_cancel`
        /// observed right after the suffix prefill returns (but before any
        /// decode work) must stop with `Interrupt`, generate zero tokens, and
        /// leave state usable for a later uncancelled call on the same
        /// conversation.
        #[test]
        fn cross_turn_cache_and_cancel_after_prefill_leaves_state_usable() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(9, 3);

            // Turn 1: establish a saved entry.
            let turn1 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "a",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("turn 1 must not error");
            assert!(turn1.output.generated_tokens > 0);

            // Turn 2: should_cancel is false on the first poll (checkpoint 1,
            // before the suffix prefill) and true on the second (checkpoint 2,
            // immediately after it returns) -- so the suffix prefill runs but
            // no decode work ever does.
            let poll_count = std::cell::Cell::new(0u32);
            let turn2 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || {
                        let n = poll_count.get() + 1;
                        poll_count.set(n);
                        n >= 2
                    },
                )
                .expect("a checkpoint-2 cancel must not surface as an engine error");
            assert!(
                poll_count.get() >= 2,
                "precondition: should_cancel must have been polled at least twice \
                 (checkpoint 1 then checkpoint 2) for this test to exercise checkpoint 2"
            );
            assert_eq!(
                turn2.output.stop_reason,
                Some(StopReason::Interrupt),
                "a checkpoint-2 cancel (right after the suffix prefill) must stop \
                 with Interrupt"
            );
            assert_eq!(
                turn2.output.generated_tokens, 0,
                "a checkpoint-2 cancel must not generate any tokens -- the suffix \
                 prefill produced only the (unsampled) next-token logits"
            );

            // Turn 3: uncancelled call on the same conversation. If checkpoint
            // 2's early return had left live KV/GDN state or the retained
            // cache entry inconsistent, this would either error or diverge.
            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming("ab", &tokenizer, &gen_cfg, |_, _| true)
                .expect("reference generate_streaming must not error");
            let turn3 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("turn 3 must not error after a checkpoint-2-cancelled turn 2");
            assert_eq!(
                turn3.output.token_ids, reference_out.token_ids,
                "post-checkpoint-2-cancel generation must still match full re-prefill exactly"
            );
        }

        /// Checkpoint 3 of the cancellation contract: a `should_cancel`
        /// observed at the top of a decode iteration, after at least one token
        /// has already been forwarded, must stop with `Interrupt`, report
        /// exactly the tokens actually forwarded before the cancel was
        /// observed, and -- per the doc comment on
        /// `generate_streaming_with_prefix_cache_and_cancel` -- this case is
        /// state-consistent and safe to save: a later append onto exactly the
        /// text produced so far must still hit `ExactAppend` and match a full
        /// re-prefill of the same extended conversation.
        #[test]
        fn cross_turn_cache_and_cancel_mid_decode_leaves_state_usable() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(17, 4);

            // should_cancel is polled once at checkpoint 1, once at checkpoint
            // 2, then once per decode iteration at checkpoint 3. Cancel on the
            // second decode-loop poll (the 4th poll overall) so exactly two
            // tokens (the prefill-sampled one plus one decode-loop token) are
            // forwarded before the cancelled iteration.
            let poll_count = std::cell::Cell::new(0u32);
            let turn1 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    "ab",
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || {
                        let n = poll_count.get() + 1;
                        poll_count.set(n);
                        n >= 4
                    },
                )
                .expect("a mid-decode cancel must not surface as an engine error");
            assert_eq!(
                turn1.output.stop_reason,
                Some(StopReason::Interrupt),
                "a checkpoint-3 (mid-decode) cancel must stop with Interrupt"
            );
            assert!(
                turn1.output.generated_tokens >= 1
                    && turn1.output.generated_tokens < gen_cfg.max_new_tokens,
                "a checkpoint-3 cancel must report exactly the tokens forwarded before \
                 the cancel was observed, not zero and not the full cap: got {}",
                turn1.output.generated_tokens
            );

            // The conversation through exactly the delivered text, plus a new
            // suffix: resubmitting the cancelled turn's own history
            // byte-for-byte with nothing new to append is itself a
            // FullRefill case (see `cross_turn_cache_exact_equal_retry_full_refills`),
            // so a real client turn always adds at least one new token before
            // its next request.
            let history = format!("ab{}", turn1.output.text);
            let followup_prompt = format!("{history}q");

            // Reference: the full uncancelled conversation through this exact
            // point, on a fresh state.
            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming(&followup_prompt, &tokenizer, &gen_cfg, |_, _| true)
                .expect("reference generate_streaming must not error");

            // A follow-up append onto exactly the delivered text must hit
            // ExactAppend, proving the cancelled turn's save left a
            // consistent, reusable boundary.
            let turn2 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    &followup_prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("follow-up turn after mid-decode cancel must not error");
            assert_eq!(
                turn2.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "a mid-decode cancel is state-consistent and safe to save -- the \
                 follow-up append must reuse it, not fall back to FullRefill"
            );
            assert_eq!(
                turn2.output.token_ids, reference_out.token_ids,
                "post-mid-decode-cancel generation must still match full re-prefill exactly"
            );
        }

        /// Client-disconnect contract, distinct from the `should_cancel` tests
        /// above: `on_token` returning `false` mid-decode -- the SSE-send-failed
        /// signal a real HTTP disconnect produces -- must never let a later
        /// request be served text the client was never actually sent.
        /// Re-issuing the ORIGINAL (pre-disconnect) prompt must reproduce the
        /// reference output for that original prompt exactly, proving the
        /// retained entry cannot silently graft the undelivered continuation
        /// onto a request that never asked for it.
        #[test]
        fn cross_turn_cache_and_cancel_on_token_disconnect_never_serves_undelivered_tokens() {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let gen_cfg = cross_turn_test_gen_cfg(31, 3);
            let prompt = "ab".to_string();

            // Simulate an SSE client that hangs up after its first delta: the
            // callback returns `false` from then on, exactly like
            // `run_worker_loop`'s `on_token` once `cb_tx.send` starts failing.
            let sent_count = std::cell::Cell::new(0u32);
            let disconnect = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    &prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_delta, _id| {
                        let n = sent_count.get() + 1;
                        sent_count.set(n);
                        n < 2
                    },
                    || false,
                )
                .expect("a disconnect must not surface as an engine error");
            assert_eq!(
                disconnect.output.stop_reason,
                Some(StopReason::Interrupt),
                "on_token returning false must stop with Interrupt"
            );

            // The client only ever has the original prompt -- it never saw
            // `disconnect.output.text`. Re-issuing exactly that original
            // prompt must reproduce the same output a fresh full re-prefill
            // of that prompt would: the planner's exact-prefix check can only
            // ExactAppend when the shared length matches the represented
            // length, so a shorter re-submitted prompt cannot silently
            // inherit the undelivered suffix.
            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference_out = reference_state
                .generate_streaming(&prompt, &tokenizer, &gen_cfg, |_, _| true)
                .expect("reference generate_streaming must not error");
            let replay = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    &prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("re-issuing the original prompt must not error");
            assert_eq!(
                replay.output.token_ids, reference_out.token_ids,
                "re-issuing exactly the client's last-known prompt must reproduce the \
                 same output a full re-prefill would -- the client can never receive \
                 tokens generated after it disconnected"
            );
        }

        /// Regression test: an `on_token` rejection mid-decode must exclude the
        /// rejected token from the persisted cache boundary, not just leave a
        /// safe-by-coincidence fallback. This is a stronger check than output
        /// parity alone (re-submitting a *shorter*, already-fully-cached prompt
        /// always falls back to `FullRefill` regardless of what garbage the
        /// cache might hold underneath, which would silently mask this bug) --
        /// it inspects the reuse *plan* the corrupted-vs-fixed cache entry
        /// produces for a follow-up prompt that extends past exactly the
        /// accepted tokens.
        #[test]
        fn cross_turn_cache_and_cancel_on_token_rejection_excludes_rejected_token_from_reuse_plan()
        {
            let Some(_) = metal::Device::system_default() else {
                return;
            };
            let _gpu_guard = gpu_test_lock();

            let tokenizer = single_char_vocab_tokenizer();
            let (mut cfg, weights) = tiny_hybrid_fixture();
            cfg.eos_token_id = u32::MAX;

            let slot_id = crate::kv_cache::CrossTurnSlotId::DEFAULT;
            let prompt = "ab".to_string();
            let prompt_len = tokenizer.tokenize(&prompt).real_length;
            let gen_cfg = cross_turn_test_gen_cfg(41, 3);

            // Deterministic (temperature 0, top_k 1): an independent, uncached
            // run of the same prompt/config tells us exactly which token the
            // decode loop's first iteration will reject below, without
            // hardcoding a sampled char that could drift with the fixture.
            let mut reference_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let reference = reference_state
                .generate_streaming(&prompt, &tokenizer, &gen_cfg, |_, _| true)
                .expect("reference generate_streaming must not error");
            assert!(
                reference.token_ids.len() >= 2,
                "fixture must generate at least 2 tokens for this test to reach the \
                 mid-decode on_token rejection branch"
            );
            let accepted_id = reference.token_ids[0];
            let rejected_id = reference.token_ids[1];
            let accepted_text = decode_tokens(&tokenizer, &[accepted_id]);
            let rejected_text = decode_tokens(&tokenizer, &[rejected_id]);

            // A follow-up suffix char guaranteed to diverge from whatever the
            // (buggy or fixed) cache entry actually holds at the rejected
            // token's position.
            let diverging_char = ('a'..='z')
                .chain('A'..='Z')
                .map(|c| c.to_string())
                .find(|c| c != &rejected_text)
                .expect("single_char_vocab_tokenizer has 52 letters, at least one differs");

            let mut state = MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let call_count = std::cell::Cell::new(0u32);
            let turn1 = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    &prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_delta, _id| {
                        let n = call_count.get() + 1;
                        call_count.set(n);
                        // Accept only the first generated token (the
                        // pre-decode-loop prefill sample); reject the second,
                        // which is produced inside the decode loop -- the
                        // branch finding 1 patches.
                        n < 2
                    },
                    || false,
                )
                .expect("on_token rejection must not surface as an engine error");
            assert_eq!(
                turn1.output.stop_reason,
                Some(StopReason::Interrupt),
                "on_token returning false must stop with Interrupt"
            );
            assert_eq!(
                turn1.output.token_ids.first().copied(),
                Some(accepted_id),
                "the accepted token must match the deterministic reference"
            );

            // The client only ever received `accepted_text`; it never saw
            // `rejected_text`. Its own next request extends the conversation
            // from what it actually has, plus new content of its own.
            let followup_prompt = format!("{prompt}{accepted_text}{diverging_char}");
            let followup = state
                .generate_streaming_with_prefix_cache_and_cancel(
                    slot_id,
                    &followup_prompt,
                    &tokenizer,
                    &gen_cfg,
                    |_, _| true,
                    || false,
                )
                .expect("follow-up turn must not error");

            // The reuse plan's own reported boundary is the direct check:
            // it must reuse through exactly `prompt_len + 1` tokens (the
            // prompt plus the one token the client actually received) and
            // never through `prompt_len + 2` (prompt plus the rejected
            // token). Without the finding-1 fix, the persisted entry's
            // `represented_len` is `prompt_len + 2`, its trailing token is
            // `rejected_id` (not `diverging_char`'s id), so the shared
            // prefix against `followup_prompt`'s tokens stops at
            // `prompt_len + 1` -- short of the (wrong) `represented_len` --
            // and the planner falls back to `FullRefill` instead, with
            // `reused_tokens == 0`.
            assert_eq!(
                followup.cache.mode,
                crate::kv_cache::PrefixReuseMode::ExactAppend,
                "a follow-up that extends exactly past the tokens the client actually \
                 received must reuse via ExactAppend; FullRefill here means the \
                 persisted cache entry still includes the token on_token rejected"
            );
            assert_eq!(
                followup.cache.reused_tokens,
                prompt_len + 1,
                "the reused boundary must cover the prompt plus exactly the one \
                 accepted token -- not the rejected token"
            );

            // Output parity: the follow-up's result must match an independent
            // full re-prefill of the same follow-up prompt.
            let mut parity_state =
                MetalQwen35State::new(&weights, &cfg, 64).expect("tiny hybrid fixture");
            let parity_reference = parity_state
                .generate_streaming(&followup_prompt, &tokenizer, &gen_cfg, |_, _| true)
                .expect("parity reference generate_streaming must not error");
            assert_eq!(
                followup.output.token_ids, parity_reference.token_ids,
                "ExactAppend reuse must reproduce exactly what a full re-prefill of the \
                 follow-up prompt would produce"
            );
        }

        // -----------------------------------------------------------------------
        // Grammar fail-closed integration tests (#611)
        //
        // These three tests are the hardware-gated end-to-end counterpart to the
        // pure-function `has_finite_logit_tests` module further down this file:
        // that module proves the *predicate* is correct in isolation, these prove
        // it is actually *wired in* at each real public Metal entry point, using
        // the same technique as the CPU reference test
        // `grammar_wiring_mask_logits_called_in_generate` in
        // `model/qwen35/generation.rs`: a `GrammarEngine` built over a vocab
        // table of all-empty byte sequences. `VocabPartition::build` rejects
        // empty entries (they can never advance the PDA), so the precomputed
        // bitmask for the initial state is all-zeros and `mask_logits` sets
        // every one of `tiny_hybrid_fixture`'s 32 logits to `NEG_INFINITY`
        // before the very first sample — a real, not simulated, all-blocked
        // mask flowing through the real Metal forward path.
        //
        // Scope: these three cover the post-prefill masking site in each
        // function. The decode-loop site — a second, structurally identical
        // `has_finite_logit` guard a few lines below the prefill one in each
        // of the three functions (`generate`, `generate_streaming_with_cancel`,
        // `generate_streaming_with_prefix_cache_inner`) — is reachable only
        // from step 2 onward and needs a grammar that allows exactly one
        // token and then blocks everything. #611 (medium
        // finding): that gap is covered separately by the
        // "DECODE-LOOP integration tests" block below this one, which builds
        // exactly that allow-then-block fixture.
        //
        // Mutation sensitivity (all three): reverting the Metal-side
        // `has_finite_logit` guard at the corresponding prefill site (or
        // stubbing it to always return `true`) leaves the all-`NEG_INFINITY`
        // row in place; the sampler's non-finite-max short-circuit then
        // silently returns token 0 and each `matches!(result, Err(...))`
        // assertion below fails instead of passing — this was verified by
        // temporarily reverting the guard and re-running these three tests
        // (see PR description).

        /// #611: `generate`'s post-prefill grammar-masking site must fail
        /// closed via `has_finite_logit`, exactly like the CPU path.
        #[test]
        fn generate_fails_closed_on_all_blocking_grammar() {
            let enforce = std::env::var_os("LATTICE_METAL_TEST_ENFORCE").is_some();
            let Some(_) = metal::Device::system_default() else {
                assert!(
                    !enforce,
                    "LATTICE_METAL_TEST_ENFORCE=1 but no Metal device present"
                );
                return;
            };
            let _guard = gpu_test_lock();

            use crate::error::InferenceError;
            use crate::grammar::{GrammarEngine, GrammarSpec};
            use crate::model::qwen35_config::GenerateConfig;
            use std::sync::Arc;

            let tokenizer = single_char_vocab_tokenizer();
            let (cfg, weights) = tiny_hybrid_fixture();
            let mut state = MetalQwen35State::new(&weights, &cfg, 32).expect("tiny hybrid fixture");

            // vocab_size=32 in `tiny_hybrid_fixture`; an all-empty-byte-sequence
            // vocab table makes every one of the 32 entries unreachable by the
            // PDA, so the initial-state mask blocks every logit.
            let vocab_bytes: Vec<Vec<u8>> = vec![vec![]; 32];
            let spec = GrammarSpec::Gbnf("root ::= \"ok\"\n".to_string());
            let engine = Arc::new(
                GrammarEngine::new(&spec, vocab_bytes)
                    .expect("grammar engine builds with empty vocab"),
            );

            let gen_cfg = GenerateConfig {
                max_new_tokens: 1,
                temperature: 0.0,
                top_k: 1,
                top_p: 1.0,
                repetition_penalty: 1.0,
                seed: Some(1),
                stop_token_ids: vec![],
                enable_thinking: false,
                enable_mtp: Some(false),
                grammar: Some(engine),
                stop_strings: vec![],
                reasoning_budget: None,
                logprobs: None,
            };

            let result = state.generate("a", &tokenizer, &gen_cfg);
            assert!(
                matches!(result, Err(InferenceError::InvalidInput(_))),
                "grammar blocking every token must fail closed via generate(); got {result:?}"
            );
        }

        /// #611: `generate_streaming`'s post-prefill grammar-masking site must
        /// fail closed too. `generate_streaming` is a pure
        /// `should_cancel = || false` delegate to
        /// `generate_streaming_with_cancel` (see that method's doc comment),
